#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void three_way_quicksort(int arr[], int low, int high) {
    if (low >= high) return;

    // Random pivot selection
    srand(time(NULL));
    int pivot_idx = low + rand() % (high - low + 1);
    int pivot = arr[pivot_idx];

    // Three pointers: lt (less than), gt (greater than), i (current)
    int lt = low;      // arr[low..lt-1] < pivot
    int gt = high;     // arr[gt+1..high] > pivot
    int i = low;       // arr[lt..i-1] == pivot

    while (i <= gt) {
        if (arr[i] < pivot) {
            // Swap arr[i] and arr[lt], increment both
            int temp = arr[i];
            arr[i] = arr[lt];
            arr[lt] = temp;
            lt++;
            i++;
        } else if (arr[i] > pivot) {
            // Swap arr[i] and arr[gt], decrement gt
            int temp = arr[i];
            arr[i] = arr[gt];
            arr[gt] = temp;
            gt--;
            // Don't increment i, need to check swapped element
        } else {
            // arr[i] == pivot
            i++;
        }
    }

    // Recursively sort three partitions
    three_way_quicksort(arr, low, lt - 1);   // < pivot
    three_way_quicksort(arr, gt + 1, high);  // > pivot
    // Elements equal to pivot are already in correct position
}

int main() {
    int arr[] = {4, 2, 4, 6, 4, 1, 4, 8};
    int n = sizeof(arr) / sizeof(arr[0]);

    printf("Original: ");
    for (int i = 0; i < n; i++) printf("%d ", arr[i]);

    three_way_quicksort(arr, 0, n - 1);

    printf("\nSorted:   ");
    for (int i = 0; i < n; i++) printf("%d ", arr[i]);

    return 0;
}

public class Introsort {
    private static final int INSERTION_THRESHOLD = 16;
    private static final int MAX_RECURSION_DEPTH = 2 * (int)(Math.floor(Math.log(2) / Math.log(2)));

    public static void sort(int[] arr) {
        if (arr == null || arr.length <= 1) return;
        introsort(arr, 0, arr.length - 1, 
                  2 * (int)(Math.log(arr.length) / Math.log(2)));
    }

    private static void introsort(int[] arr, int begin, int end, int depthLimit) {
        int n = end - begin + 1;

        if (n <= INSERTION_THRESHOLD) {
            insertionSort(arr, begin, end);
            return;
        }

        if (depthLimit == 0) {
            heapsort(arr, begin, end);
            return;
        }

        // Use last element as pivot (not randomized for Introsort)
        int pivot = partition(arr, begin, end);

        introsort(arr, begin, pivot - 1, depthLimit - 1);
        introsort(arr, pivot + 1, end, depthLimit - 1);
    }

    private static int partition(int[] arr, int begin, int end) {
        int pivot = arr[end];
        int i = begin - 1;

        for (int j = begin; j < end; j++) {
            if (arr[j] <= pivot) {
                i++;
                swap(arr, i, j);
            }
        }
        swap(arr, i + 1, end);
        return i + 1;
    }

    private static void insertionSort(int[] arr, int begin, int end) {
        for (int i = begin + 1; i <= end; i++) {
            int key = arr[i];
            int j = i - 1;
            while (j >= begin && arr[j] > key) {
                arr[j + 1] = arr[j];
                j--;
            }
            arr[j + 1] = key;
        }
    }

    private static void heapsort(int[] arr, int begin, int end) {
        // Build max heap
        for (int i = (end - begin) / 2; i >= 0; i--)
            heapify(arr, begin, end, i);

        // Extract elements
        for (int i = end; i > begin; i--) {
            swap(arr, begin, i);
            heapify(arr, begin, i - 1, 0);
        }
    }

    private static void heapify(int[] arr, int begin, int end, int i) {
        int largest = i;
        int left = 2 * (i - begin) + 1 + begin;
        int right = 2 * (i - begin) + 2 + begin;

        if (left <= end && arr[left] > arr[largest])
            largest = left;
        if (right <= end && arr[right] > arr[largest])
            largest = right;

        if (largest != i) {
            swap(arr, i, largest);
            heapify(arr, begin, end, largest);
        }
    }

    private static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
